// modint {{{

template<typename Mod>

class ModIntT {

private:

    i64 v_;  // [0,Mod::value)



    static i64 mod() { return Mod::value; }



    static i64 normalize(i64 x) {

        i64 res = x % mod();

        if(res < 0) res += mod();

        return res;

    }



